  }

  setting {
    namespace = "aws:aws:common:environments"
    name      = "DatabaseInstance"
    value     = aws_db_instance.my_db.identifier
  }

  depends_on = [aws_db_instance.my_db]
}

resource "aws_db_snapshot" "pre_deployment" {
  db_instance_identifier = aws_db_instance.my_db.identifier
  db_snapshot_identifier = "snapshot-${random_id.suffix.hex}"
}
