  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.eb_igw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

resource "aws_route_table_association" "public_subnet_1" {
  subnet_id      = aws_subnet.eb_subnet_public_1.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "public_subnet_2" {
  subnet_id      = aws_subnet.eb_subnet_public_2.id
  route_table_id = aws_route_table.public.id
}

resource "aws_db_subnet_group" "eb_db_subnet_group" {
  name       = "eb-db-subnet-group"
  subnet_ids = [aws_subnet.eb_subnet_public_1.id, aws_subnet.eb_subnet_public_2.id]

  tags = {
    Name = "eb-db-subnet-group"
  }
}

resource "aws_db_instance" "shared_rds" {
  identifier           = "shared-rds"
  db_name              = "shared_rds"
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  username             = "admin"
  password             = random_password.db.result
  db_subnet_group_name = aws_db_subnet_group.eb_db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.eb_env_sg.id]
  skip_final_snapshot  = true
  publicly_accessible  = false

  tags = {
    Name = "shared_rds"
  }
}

resource "aws_elastic_beanstalk_application" "eb_app" {
  name        = "shared-eb-app"
  description = "Elastic Beanstalk application for shared environments"
}

resource "aws_elastic_beanstalk_environment" "eb_env_1" {
  name                = "eb-env-1"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.3.6 running Python 3.9"

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = aws_vpc.eb_vpc.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = aws_subnet.eb_subnet_public_1.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "PublicIP"
    value     = "true"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "3"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:ec2:instances"
    name      = "SecurityGroups"
    value     = aws_security_group.eb_env_sg.id
  }
}

resource "aws_elastic_beanstalk_environment" "eb_env_2" {
  name                = "eb-env-2"
  application         = aws_elastic_beanstalk_application.eb_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.3.6 running Python 3.9"

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = aws_vpc.eb_vpc.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = aws_subnet.eb_subnet_public_2.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "PublicIP"
    value     = "true"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "3"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:ec2:instances"
    name      = "SecurityGroups"
    value     = aws_security_group.eb_env_sg.id
  }
}
