  enumeration_value {
    value = "mushrooms"
  }
  enumeration_value {
    value = "sausage"
  }
  enumeration_value {
    value = "onions"
  }
  enumeration_value {
    value = "bacon"
  }
  enumeration_value {
    value = "extra cheese"
  }
}

