resource "aws_lex_intent" "order_pizza_intent" {
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  slot {
    name                 = "PizzaSize"
    slot_type            = "AMAZON.US_SIZE"
    value_elicitation_prompt = {
      message = {
        content      = "What size pizza would you like?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
    priority           = 1
    sample_utterances  = ["large", "medium", "small"]
    slot_constraint    = "Required"
  }

  slot {
    name                 = "Toppings"
    slot_type            = "CustomToppings"
    value_elicitation_prompt = {
      message = {
        content      = "What toppings do you want on your pizza?"
        content_type = "PlainText"
      }
      max_attempts = 3
    }
    priority           = 2
    sample_utterances  = ["pepperoni", "mushrooms", "sausage", "onions"]
    slot_constraint    = "Required"
  }

  confirmation_prompt = {
    message = {
      content      = "You want a {PizzaSize} pizza with {Toppings}, correct?"
      content_type = "PlainText"
    }
    max_attempts = 2
  }

  rejection_statement = {
    message = {
      content      = "Okay, let's start over."
      content_type = "PlainText"
    }
  }

  sample_utterances = [
    "I want to order a pizza",
    "I'd like a pizza",
    "Can I get a pizza with {Toppings}"
  ]

  follow_up_prompt = {
    prompt = {
      message = {
        content      = "Would you like to add a drink to your order?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
    rejection_statement = {
      message = {
        content      = "Alright, no drink added."
        content_type = "PlainText"
      }
    }
  }
}

