    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }

  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_security_group" "allow_ssh" {
  name        = "allow_ssh"
  description = "Allow SSH inbound traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow_ssh"
  }
}

resource "aws_launch_template" "ec2_template" {
  name_prefix   = "ec2-launch-template-"
  image_id      = "ami-0a54c80724b829c09" # Amazon Linux 2 latest as of recent data (verify in region)
  instance_type = "t3.micro"
  key_name      = "my-key-pair" # Replace with your key pair
  vpc_security_group_ids = [aws_security_group.allow_ssh.id]

  user_data = base64encode(<<-EOF
              #!/bin/bash
              echo "Hello, World" > /home/ec2-user/hello.txt
              EOF
  )

  tag_specifications {
    resource_type = "instance"
    tags = {
      Name = "ec2-fleet-instance"
    }
  }
}

resource "aws_ec2_fleet" "example_fleet" {
  target_capacity_specification {
    total_target_capacity = 9
    on_demand_target_capacity = 5
    spot_target_capacity = 4
    default_target_capacity_type = "on-demand"
  }

  launch_template_config {
    launch_template_specification {
      name    = aws_launch_template.ec2_template.name
      version = "$$Latest"
    }

    overrides {
      subnet_id = aws_subnet.public.id
    }
  }

  fleet_type = "maintain" # Ensures fleet maintains capacity if instances terminate
}
