# Attach a policy to allow IAM user to interact with ElastiCache via IAM authentication
resource "aws_iam_user_policy" "elasticache_user" {
  name = "elasticache_user_policy"
  user = aws_iam_user.elasticache_user.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "elasticache:DescribeCacheClusters",
          "elasticache:DescribeUsers",
          "elasticache:DescribeUserGroups",
          "elasticache:ModifyUser",
          "elasticache:ListAllowedNodeTypeModifications"
        ]
        Resource = "*"
      }
    ]
  })
}

# Note: To use IAM authentication with ElastiCache (for Redis), you must:
# 1. Enable IAM authentication on the ElastiCache Redis cluster.
# 2. Use the IAM credentials (access key + secret) to generate an auth token.
# This configuration sets up the IAM user and ElastiCache user, but actual IAM authentication
# happens outside Terraform (e.g., via AWS CLI or application code using AWS SDK).

