resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_cloudwatch_log_group" "msk_logs" {
  name = "msk-cluster-logs-${random_id.suffix.hex}"
  retention_in_days = 7
}

resource "aws_kafka_cluster" "msk_cluster" {
  cluster_name           = "managed-msk-cluster-${random_id.suffix.hex}"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = [
      aws_subnet.subnet1.id,
      aws_subnet.subnet2.id,
      aws_subnet.subnet3.id
    ]
    security_groups = [aws_security_group.msk_sg.id]
    storage_info {
      ebs_storage_info {
        volume_size = 100
      }
    }
  }

  logging_info {
    broker_logs {
      cloud_watch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
    }
  }

  # Required AWS MSK VPC configuration
  depends_on = [
    aws_internet_gateway.igw,
    aws_route_table.route
  ]
}

# Required networking resources
