            }
            node_exporter {
                enabled_in_broker = true
            }
        }
    }

    logging_info {
        broker_logs {
            cloudwatch_logs {
                enabled = false
            }
            firehose {
                enabled = false
            }
            s3 {
                enabled = true
                bucket = aws_s3_bucket.bucket.id
                prefix = "logs/msk-"
            }
        }
    }
}

