  bucket = "autograder-source-${random_id.suffix.hex}"
  versioning {
    enabled = true
  }
  tags = {
    Name        = "Autograder Source Code Bucket"
    Environment = "Production"
  }
}

resource "aws_s3_bucket" "autograder_artifacts" {
  bucket = "autograder-artifacts-${random_id.suffix.hex}"
  versioning {
    enabled = true
  }
  tags = {
    Name        = "Autograder Artifacts Bucket"
    Environment = "Production"
  }
}

resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "codebuild_policy" {
  name = "autograder-codebuild-policy-${random_id.suffix.hex}"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.autograder_source.arn,
          "${aws_s3_bucket.autograder_source.arn}/*",
          aws_s3_bucket.autograder_artifacts.arn,
          "${aws_s3_bucket.autograder_artifacts.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project-${random_id.suffix.hex}"
  description   = "Autograder for CS class assignments"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograder_artifacts.bucket
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/example-user/cs-class-assignments.git"
    git_clone_depth = 1
    buildspec = "buildspec.yml"
  }

  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = true

    environment_variable {
      name  = "ARTIFACT_BUCKET"
      value = aws_s3_bucket.autograder_artifacts.bucket
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name = "/aws/codebuild/autograder"
      stream_name = "autograder-stream"
    }
    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.autograder_artifacts.bucket}/logs"
    }
  }

  tags = {
    Name = "AutograderProject"
  }
}

resource "aws_cloudwatch_log_group" "autograder_logs" {
  name              = "/aws/codebuild/autograder"
  retention_in_days = 7
}
