  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograder-vpc-${random_id.suffix.hex}"
  }
}

resource "aws_internet_gateway" "autograder_igw" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-igw-${random_id.suffix.hex}"
  }
}

resource "aws_subnet" "autograder_subnet" {
  vpc_id                  = aws_vpc.autograder_vpc.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = false
  availability_zone       = "us-west-2a"

  tags = {
    Name = "autograder-subnet-${random_id.suffix.hex}"
  }
}

resource "aws_route_table" "autograder_private_rt" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-private-rt-${random_id.suffix.hex}"
  }
}

resource "aws_route_table_association" "autograder_rta" {
  subnet_id      = aws_subnet.autograder_subnet.id
  route_table_id = aws_route_table.autograder_private_rt.id
}

resource "aws_security_group" "autograder_sg" {
  name        = "autograder-sg-${random_id.suffix.hex}"
  description = "Security group for autograder build environment"
  vpc_id      = aws_vpc.autograder_vpc.id

  # Allow outbound traffic for updates (if needed), but we'll restrict internet access via VPC design
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow inbound SSH (for debugging if needed) and only from trusted IP or VPC
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  tags = {
    Name = "autograder-sg-${random_id.suffix.hex}"
  }
}

resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project-${random_id.suffix.hex}"
  description   = "Autograder for CS class assignments"
  build_timeout = 60
  queued_timeout = 60

  source {
    type      = "GITHUB"
    location  = "https://github.com/example-user/cs-class-submissions.git"
    git_clone_depth = 1
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false

    environment_variable {
      name  = "SUBMISSION_REPO"
      value = "https://github.com/example-user/cs-class-submissions.git"
    }
  }

  service_role = aws_iam_role.codebuild_role.arn

  vpc_config {
    vpc_id            = aws_vpc.autograder_vpc.id
    subnets           = [aws_subnet.autograder_subnet.id]
    security_group_ids = [aws_security_group.autograder_sg.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/autograder-${random_id.suffix.hex}"
      stream_name = "main"
    }
    s3_logs {
      status = "ENABLED"
    }
  }
}

