  vpc_id                  = aws_vpc.autograder_vpc.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = false
  availability_zone       = "us-west-2a"

  tags = {
    Name = "autograder-subnet-${random_id.suffix.hex}"
  }
}

resource "aws_route_table" "autograder_private_rt" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-private-rt-${random_id.suffix.hex}"
  }
}

resource "aws_route_table_association" "autograder_rta" {
