  route_table_id = aws_route_table.autograder_private_rt.id
}

resource "aws_security_group" "autograder_sg" {
  name        = "autograder-sg-${random_id.suffix.hex}"
  description = "Security group for autograder build environment"
  vpc_id      = aws_vpc.autograder_vpc.id

  # Allow outbound traffic for updates (if needed), but we'll restrict internet access via VPC design
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow inbound SSH (for debugging if needed) and only from trusted IP or VPC
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  tags = {
    Name = "autograder-sg-${random_id.suffix.hex}"
  }
}

resource "aws_codebuild_project" "autograder" {
