  policy_arn = aws_iam_policy.codebuild_policy.arn
}

resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project-${random_id.suffix.hex}"
  description   = "Autograder for CS class assignments"
  build_timeout = 60
  queued_timeout = 480

  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  cache {
    type = "S3"
    location = aws_s3_bucket.results_bucket.bucket
  }

  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false

    environment_variable {
      name  = "S3_RESULTS_BUCKET"
      value = aws_s3_bucket.results_bucket.bucket
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/example/student-repo.git"
    git_clone_depth = 1
    buildspec = "buildspec.yml"
  }

  vpc_config {
    vpc_id            = aws_vpc.autograder_vpc.id
    subnets           = [aws_subnet.private_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  tags = [
    {
      key   = "Project"
      value = "CS-Autograder"
    }
  ]
}

# Optional: S3 bucket policy to prevent public access
resource "aws_s3_bucket_policy" "no_public_access" {
  bucket = aws_s3_bucket.student_code_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid = "DenyUnEncryptedObjectUploads"
        Effect = "Deny"
        Principal = "*"
        Action = "s3:PutObject"
        Resource = "${aws_s3_bucket.student_code_bucket.arn}/*"
        Condition = {
          StringNotEquals = {
            "s3:x-amz-server-side-encryption" = "aws:kms"
          }
        }
      }
    ]
  })
}

output "autograder_s3_bucket" {
  value = aws_s3_bucket.student_code_bucket.bucket
}

output "autograder_results_bucket" {
  value = aws_s3_bucket.results_bucket.bucket
}

output "codebuild_project_name" {
  value = aws_codebuild_project.autograder.name
}
