  }
}

resource "aws_lb" "streaming_lb" {
  name               = "streaming-lb-${random_id.suffix.hex}"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.web_servers.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false

  tags = {
    Environment = "production"
    Project     = "video-streaming"
  }
}

resource "aws_lb_target_group" "web_targets" {
  name     = "web-targets"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    path                = "/"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
  }

  tags = {
    Name = "web-targets"
  }
}

resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.streaming_lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.web_targets.arn
  }
}

resource "aws_lb_target_group_attachment" "web_server_attachments" {
  count            = 2
  target_group_arn = aws_lb_target_group.web_targets.arn
  target_id        = aws_instance.web_server[count.index].id
  port             = 80
}

resource "aws_route53_zone" "streaming_domain" {
  name = "videostreaming.example.com"
}

resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.streaming_domain.zone_id
  name    = "www.videostreaming.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.streaming_lb.dns_name
    zone_id                = aws_lb.streaming_lb.zone_id
    evaluate_target_health = true
  }
}
