resource "aws_iam_role" "dlm_role" {
  name = "dlm-glacier-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "dlm_policy" {
  role       = aws_iam_role.dlm_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSDataLifecycleManagerServiceRole"
}

resource "aws_dlm_lifecycle_policy" "glacier_policy" {
  description        = "Glacier backup via Data Lifecycle Manager"
  execution_role_arn = aws_iam_role.dlm_role.arn
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]

    schedule {
      name = "Glacier-schedule"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["23:45"]
      }

      retain_rule {
        count = 5
      }

      fast_restore_rule {
        count         = 1
        availability_zone = "us-west-2a"
      }

      archive_rule {
        retain_rule {
          # Retain archived snapshots for 90 days before deletion
          retention_days = 90
        }

        // Use Glacier as the archive tier
        archive_tier = "GLACIER"
      }
    }

    action {
      name      = "archive-snapshots"
      action_id = "archive-snapshots"

      cross_region_copy {
        target = "us-east-1"

        encryption_configuration {}

        retention_rule {
          # Retain cross-region copies for 90 days
          interval      = 90
          interval_unit = "DAYS"
        }
      }
    }
  }
}

