resource "aws_glacier_vault" "example" {
  name = "example-vault"

  # Enable Vault Lock policy
  policy = data.aws_iam_policy_document.vault_lock.json
}

data "aws_iam_policy_document" "vault_lock" {
  statement {
    sid       = "DenyIncompleteMultipartUpload"
    effect    = "Deny"
    actions   = ["glacier:UploadArchive", "glacier:InitiateMultipartUpload", "glacier:AbortMultipartUpload"]
    resources = [aws_glacier_vault.example.arn]

    condition {
      test     = "NumericLessThan"
      variable = "glacier:ContentLength"
      values   = ["4096"]
    }

    principals {
      type        = "*"
      identifiers = ["*"]
    }
  }

  statement {
    sid       = "PreventRemovalOfVaultLock"
    effect    = "Deny"
    actions   = ["glacier:DeleteVault", "glacier:DeleteVaultNotifications", "glacier:SetVaultAccessPolicy", "glacier:SetVaultNotifications"]
    resources = [aws_glacier_vault.example.arn]

    condition {
      test     = "Bool"
      variable = "glacier:VaultLockPresent"
      values   = ["false"]
    }

    principals {
      type        = "*"
      identifiers = ["*"]
    }
  }
}

resource "aws_glacier_vault_lock" "example" {
  vault_name = aws_glacier_vault.example.name
  policy     = data.aws_iam_policy_document.vault_lock.json

  # Pending policy can be locked immediately (simulate immediate lock for example)
  ignore_deletion_error = true
}

